def _to_bits(nats: float) -> float:
    return float(nats) / _LN2

def _split_claims(answer: str, mode: str, max_claims: int) -> List[str]:
    a = (answer or "").strip()
    if not a:
        return []

    if mode == "lines":
        raw = [ln.strip() for ln in a.splitlines() if ln.strip()]
    else:
        raw = [s.strip() for s in _SENTENCE_SPLIT_RE.split(a) if s.strip()]

    cite_prefix_re = re.compile(r"^\s*(?:\[(?:[A-Za-z]\w*|\d+)\]\s*)+")

    merged: List[str] = []
    for seg in raw:
        # If a segment begins with citations and then continues with content,
        # move the citation prefix back onto the previous claim.
        if merged:
            m = cite_prefix_re.match(seg)
            if m:
                prefix = seg[: m.end()].strip()
                rest = seg[m.end() :].strip()
                if prefix and rest:
                    merged[-1] = (merged[-1] + " " + prefix).strip()
                    seg = rest

        remainder = _DEFAULT_CITE_RE.sub("", seg)
        remainder = re.sub(r"[\\s,;:.\\-\u2013\u2014!?]+", "", remainder)
        cites_only = (remainder == "") and bool(_DEFAULT_CITE_RE.search(seg))
        if cites_only and merged:
            merged[-1] = (merged[-1] + " " + seg).strip()
        else:
            merged.append(seg)

    return merged[: max(1, int(max_claims))]

def scrub_spans_by_id(spans: Sequence[Any], cites: Sequence[str], *, placeholder: str = "[REDACTED]") -> List[Any]:
    cset = {str(c) for c in cites}
    out: List[Any] = []
    for s in spans:
        sid = str(getattr(s, "sid"))
        text = str(getattr(s, "text"))
        if sid in cset:
            try:
                out.append(type(s)(sid=sid, text=placeholder))
            except Exception:
                out.append({"sid": sid, "text": placeholder})
        else:
            try:
                out.append(type(s)(sid=sid, text=text))
            except Exception:
                out.append({"sid": sid, "text": text})
    return out

@dataclass
class TokenTopK:
    """Top-K distribution at the answer-start token position."""

    pos: int
    generated_token: str
    generated_logprob: float
    topk_logprobs: Dict[str, float]
    kth_logprob: Optional[float]


def extract_answer_topk(logprobs: Any) -> TokenTopK:
    """Extract a top-K distribution for the first non-whitespace output token."""
    if logprobs is None:
        raise ValueError("logprobs is None; call the API with logprobs enabled")

    seq = list(logprobs)
    if not seq:
        raise ValueError("empty logprobs list")

    pos = 0
    for i, tokinfo in enumerate(seq):
        tok = _get_token(tokinfo)
        if tok.strip() != "":
            pos = i
            break

    tokinfo = seq[pos]
    gen_tok = _get_token(tokinfo)
    gen_lp = _get_logprob(tokinfo)
    if gen_lp is None:
        raise ValueError("missing logprob for generated token")

    top_list = _get_top_logprobs(tokinfo)
    topk: Dict[str, float] = {}
    for t in top_list:
        tt = _get_token(t)
        lp = _get_logprob(t)
        if lp is None:
            continue
        key = tt.lstrip()
        if key == "":
            continue
        topk[key] = max(topk.get(key, -math.inf), float(lp))

    kth = None
    if top_list:
        lps = [lp for lp in ([_get_logprob(t) for t in top_list]) if lp is not None]
        kth = min(lps) if lps else None

    return TokenTopK(
        pos=int(pos),
        generated_token=str(gen_tok),
        generated_logprob=float(gen_lp),
        topk_logprobs=topk,
        kth_logprob=kth,
    )

def yesprob_from_logprobs(logprobs: Any) -> YesProb:
    topk = extract_answer_topk(logprobs)
    yes_lps = [
        float(lp)
        for tok, lp in (topk.topk_logprobs or {}).items()
        if str(tok).strip().upper() == "YES"
    ]

    if yes_lps:
        p = sum(math.exp(lp) for lp in yes_lps)
        p = min(max(float(p), 0.0), 1.0)
        p_lower = p
        p_upper = p
    else:
        p_lower = 0.0
        if topk.kth_logprob is not None and math.isfinite(float(topk.kth_logprob)):
            p_upper = math.exp(float(topk.kth_logprob))
        else:
            p_upper = 1.0

    return YesProb(
        p_yes_lower=float(p_lower),
        p_yes_upper=float(p_upper),
        generated=str(topk.generated_token),
        generated_logprob=float(topk.generated_logprob),
        kth_logprob=float(topk.kth_logprob) if topk.kth_logprob is not None else None,
        topk=dict(topk.topk_logprobs),
    )

def _safe_clip(p: float, eps: float = 1e-12) -> float:
    return min(max(float(p), eps), 1.0 - eps)


def kl_bernoulli(a: float, b: float) -> float:
    a = _safe_clip(a)
    b = _safe_clip(b)
    return a * math.log(a / b) + (1 - a) * math.log((1 - a) / (1 - b))

@dataclass
class BackendConfig:
    kind: str = "openai"
    max_concurrency: int = 20
    timeout_s: Optional[float] = None
    base_url: Optional[str] = None
    api_key: Optional[str] = None


class OpenAIBackend:
    """Thin wrapper around openai backend with batch helpers (thread-pool parallelism)."""

    def __init__(self, cfg: BackendConfig):
        self.cfg = cfg

    def call_text(self, **kwargs: Any) -> TextResult:
        return call_text_chat(
            **kwargs,
            timeout_s=self.cfg.timeout_s,
            base_url=self.cfg.base_url,
            api_key=self.cfg.api_key,
        )

    def call_text_batch(self, *, prompts: Sequence[str], **kwargs: Any) -> List[TextResult]:
        max_workers = max(1, int(self.cfg.max_concurrency))
        with cf.ThreadPoolExecutor(max_workers=max_workers) as ex:
            futs = [ex.submit(self.call_text, prompt=p, **kwargs) for p in prompts]
            return [f.result() for f in futs]

    def reset_state(self) -> None:
        import gc
        gc.collect()

def make_backend(cfg: BackendConfig):
    kind = (cfg.kind or "openai").lower().strip()
    if kind == "openai":
        return OpenAIBackend(cfg)
    if kind == "gemini":
        return GeminiBackend(cfg)
    if kind == "vertex":
        return VertexBackend(cfg)
    if kind == "dummy":
        return DummyBackend()
    raise ValueError(f"Unknown backend kind: {cfg.kind!r}")

choice = resp.choices[0]
out_text = choice.message.content or ""

out_logprobs = None
if include_logprobs and getattr(choice, "logprobs", None) and getattr(choice.logprobs, "content", None):
    out_logprobs = []
    for token_info in choice.logprobs.content:
        token_data = {
            "token": token_info.token,
            "logprob": token_info.logprob,
        }
        if token_info.top_logprobs:
            token_data["top_logprobs"] = [
                {"token": t.token, "logprob": t.logprob}
                for t in token_info.top_logprobs
            ]
        out_logprobs.append(token_data)

return TextResult(text=str(out_text), response_id=getattr(resp, "id", None), logprobs=out_logprobs)

def create_server(*, project_root: Optional[Path], host: str = "127.0.0.1", port: int = 8000) -> Any:
    try:
        from mcp.server.fastmcp import FastMCP
    except ImportError as exc:  # pragma: no cover
        raise ImportError("MCP SDK not installed. Run: pip install 'mcp[cli]'") from exc

    mcp = FastMCP("berry", json_response=True, host=host, port=port)

def _default_verifier_model() -> str:
    return (
        (os.environ.get("BERRY_VERIFIER_MODEL") or "").strip()
        or (os.environ.get("BERRY_MODEL") or "").strip()
        or "gpt-4o-mini"
    )

@mcp.tool()
def detect_hallucination(
    answer: str,
    spans: List[Dict[str, str]],
    verifier_model: Optional[str] = None,
    default_target: float = 0.95,
    max_claims: int = 25,
    require_citations: bool = False,
    context_mode: str = "cited",
    timeout_s: float = 60.0,
) -> Dict[str, Any]:
    """Information-budget diagnostic per claim."""
    with _redirect_stdout_to_stderr():
        try:
            return run_detect_hallucination(
                answer=str(answer or ""),
                spans=list(spans or []),
                verifier_model=str(verifier_model or _default_verifier_model()),
                default_target=float(default_target or 0.95),
                max_claims=int(max_claims or 25),
                require_citations=bool(require_citations),
                context_mode=str(context_mode or "cited"),
                timeout_s=float(timeout_s or 60.0),
            )
        except Exception as e:
            return {"flagged": True, "under_budget": True, "error": str(e), "details": []}

@mcp.tool()
def audit_trace_budget(
    steps: List[Dict[str, Any]],
    spans: List[Dict[str, str]],
    verifier_model: Optional[str] = None,
    default_target: float = 0.95,
    require_citations: bool = False,
    context_mode: str = "cited",
    timeout_s: float = 60.0,
) -> Dict[str, Any]:
    """Score explicit (claim, cites) steps."""
    with _redirect_stdout_to_stderr():
        try:
            return run_audit_trace_budget(
                steps=list(steps or []),
                spans=list(spans or []),
                verifier_model=str(verifier_model or _default_verifier_model()),
                default_target=float(default_target or 0.95),
                require_citations=bool(require_citations),
                context_mode=str(context_mode or "cited"),
                timeout_s=float(timeout_s or 60.0),
            )
        except Exception as e:
            return {"flagged": True, "under_budget": True, "error": str(e), "details": []}
